mapper.select:
SELECT orderType, status, SUM(count) AS count FROM ( SELECT ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@RECEIPT.type} AS orderType, status, COUNT(*) AS count FROM wms_receipt_order WHERE deleted = 0
AND warehouse_id = #{warehouseId}
GROUP BY status UNION ALL SELECT ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@SHIPMENT.type} AS orderType, status, COUNT(*) AS count FROM wms_shipment_order WHERE deleted = 0
AND warehouse_id = #{warehouseId}
GROUP BY status UNION ALL SELECT ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@MOVEMENT.type} AS orderType, status, COUNT(*) AS count FROM wms_movement_order WHERE deleted = 0
AND (source_warehouse_id = #{warehouseId} OR target_warehouse_id = #{warehouseId})
GROUP BY status UNION ALL SELECT ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@CHECK.type} AS orderType, status, COUNT(*) AS count FROM wms_check_order WHERE deleted = 0
AND warehouse_id = #{warehouseId}
GROUP BY status ) t GROUP BY orderType, status ORDER BY orderType, status

SELECT date, orderType, SUM(count) AS count FROM ( SELECT DATE_FORMAT(order_time, '%Y-%m-%d') AS date, ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@RECEIPT.type} AS orderType, COUNT(*) AS count FROM wms_receipt_order WHERE deleted = 0 AND order_time >= #{beginTime} AND order_time < #{endTime}
AND warehouse_id = #{warehouseId}
GROUP BY DATE_FORMAT(order_time, '%Y-%m-%d') UNION ALL SELECT DATE_FORMAT(order_time, '%Y-%m-%d') AS date, ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@SHIPMENT.type} AS orderType, COUNT(*) AS count FROM wms_shipment_order WHERE deleted = 0 AND order_time >= #{beginTime} AND order_time < #{endTime}
AND warehouse_id = #{warehouseId}
GROUP BY DATE_FORMAT(order_time, '%Y-%m-%d') UNION ALL SELECT DATE_FORMAT(order_time, '%Y-%m-%d') AS date, ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@MOVEMENT.type} AS orderType, COUNT(*) AS count FROM wms_movement_order WHERE deleted = 0 AND order_time >= #{beginTime} AND order_time < #{endTime}
AND (source_warehouse_id = #{warehouseId} OR target_warehouse_id = #{warehouseId})
GROUP BY DATE_FORMAT(order_time, '%Y-%m-%d') UNION ALL SELECT DATE_FORMAT(order_time, '%Y-%m-%d') AS date, ${@cn.iocoder.yudao.module.wms.enums.order.WmsOrderTypeEnum@CHECK.type} AS orderType, COUNT(*) AS count FROM wms_check_order WHERE deleted = 0 AND order_time >= #{beginTime} AND order_time < #{endTime}
AND warehouse_id = #{warehouseId}
GROUP BY DATE_FORMAT(order_time, '%Y-%m-%d') ) t GROUP BY date, orderType ORDER BY date, orderType

SELECT item.id AS id, item.name AS name, IFNULL(SUM(inventory.quantity), 0) AS quantity FROM wms_inventory inventory INNER JOIN wms_item_sku sku ON sku.id = inventory.sku_id AND sku.deleted = 0 INNER JOIN wms_item item ON item.id = sku.item_id AND item.deleted = 0 WHERE inventory.deleted = 0 AND inventory.quantity > 0
AND inventory.warehouse_id = #{warehouseId}
GROUP BY item.id, item.name ORDER BY quantity DESC, item.id ASC LIMIT #{limit}

SELECT warehouse.id AS id, warehouse.name AS name, IFNULL(SUM(inventory.quantity), 0) AS quantity FROM wms_inventory inventory INNER JOIN wms_warehouse warehouse ON warehouse.id = inventory.warehouse_id AND warehouse.deleted = 0 WHERE inventory.deleted = 0 AND inventory.quantity > 0
AND inventory.warehouse_id = #{warehouseId}
GROUP BY warehouse.id, warehouse.name ORDER BY quantity DESC, warehouse.id ASC LIMIT #{limit}
